customMethods.script:
toolId = self.view.params.value
if not toolId:
	empty = {"rows": []}
	self.view.custom.state = {"selected": dict(empty), "editDraft": dict(empty)}
	return
instances = BlueRidge.Parts.Tool.getAttributeInstancesForTool(toolId) or []
loaded = []
for inst in instances:
	attr = (inst or {}).get("attr") or {}
	loaded.append({
		"id":                        attr.get("Id"),
		"toolAttributeDefinitionId": attr.get("ToolAttributeDefinitionId"),
		"definitionLabel":           attr.get("AttrName") or "",
		"value":                     attr.get("Value") if attr.get("Value") is not None else "",
		"dataType":                  attr.get("DataType") or "String",
	})
self.view.custom.state = {"selected": {"rows": loaded}, "editDraft": {"rows": [dict(r) for r in loaded]}}

toolId = self.view.params.value
if not toolId:
	BlueRidge.Common.Notify.toast("No tool selected", "Pick a tool before saving.", "warning")
	return
draft = BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.state.editDraft) or {}
rows = draft.get("rows") or []
result = BlueRidge.Parts.Tool.saveAttributesAll(toolId, rows)
BlueRidge.Common.Ui.notifyResult(result, "Attributes saved")
if result and result.get("Status"):
	self.load()

draft = dict(BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.state.editDraft) or {"rows": []})
rows = list(draft.get("rows") or [])
rows.append({
	"id":                        None,
	"toolAttributeDefinitionId": None,
	"definitionLabel":           "",
	"value":                     "",
	"dataType":                  "String",
})
draft["rows"] = rows
selected = BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.state.selected) or {"rows": []}
self.view.custom.state = {"selected": selected, "editDraft": draft}

